public enum Day {
    MONDAY, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY, SUNDAY
}

public class Main {
    enum Day {
        MONDAY, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY, SUNDAY
    }

    public static void main(String[] args) {
        Day today = Day.WEDNESDAY;
        System.out.println(today);
    }
}

public class Main {
    enum Day {
        MONDAY, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY, SUNDAY
    }

    public static void main(String[] args) {
        Day today = Day.SATURDAY;

        String type = switch (today) {
            case SATURDAY, SUNDAY -> "Weekend";
            default -> "Weekday";
        };

        System.out.println(type);
    }
}

public class Main {
    enum Planet {
        MERCURY(3.3e23, 2.4e6),
        EARTH(5.9e24, 6.4e6);

        private final double mass;
        private final double radius;

        Planet(double mass, double radius) {
            this.mass = mass;
            this.radius = radius;
        }

        double getMass() {
            return mass;
        }
    }

    public static void main(String[] args) {
        System.out.println(Planet.EARTH.getMass());
    }
}

public class Main {
    enum TrafficLight {
        RED, YELLOW, GREEN
    }

    static String action(TrafficLight light) {
        return switch (light) {
            case RED -> "Stop";
            case YELLOW -> "Slow down";
            case GREEN -> "Go";
        };
    }

    public static void main(String[] args) {
        System.out.println(action(TrafficLight.RED));
        System.out.println(action(TrafficLight.GREEN));
    }
}

